                                        context.CommitChildContext(false, ref childContext);
                                        context.EvaluatedKeyword(false, messageProvider: JsonSchemaEvaluation.ExpectedPropertyMatchesFallbackSchema, "additionalProperties"u8);
                                    }
                                    else
                                    {
                                        context.CommitChildContext(true, ref childContext);
                                        context.AddLocalEvaluatedProperty(objectValidation_propertyCount);
                                        context.EvaluatedKeyword(true, messageProvider: JsonSchemaEvaluation.ExpectedPropertyMatchesFallbackSchema, "additionalProperties"u8);
                                    }
                                }
                            }

                            objectValidation_propertyCount++;
                        }

                        // Do a quick test to see if we have all of the required bits set in each element
                        if ((~(requiredPropertyChildHandler_seenItems[0]) & RequiredBitMask0) == 0)
                        {
                            if (context.HasCollector)
                            {
                                context.EvaluatedKeywordForProperty(true, 0, RequiredPropertyActionPresent, "action"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 1, RequiredPropertyArgsPresent, "args"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 2, RequiredPropertyDescriptionPresent, "description"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 3, RequiredPropertyDisplayNamePresent, "display-name"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 4, RequiredPropertyFollowedByPresent, "followed-by"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 5, RequiredPropertyMenuCodePresent, "menu-code"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 6, RequiredPropertyModulePresent, "module"u8, "required"u8);
