                                context.EvaluatedKeywordForProperty(true, 10, RequiredPropertyPrecededByPresent, "preceded-by"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 11, RequiredPropertyRequiredPresent, "required"u8, "required"u8);
                                context.EvaluatedKeywordForProperty(true, 12, RequiredPropertySkillPresent, "skill"u8, "required"u8);
                            }
                        }
                        else if (!context.HasCollector)
                        {
                            context.EvaluatedBooleanSchema(false);
                            return;
                        }
                        else
                        {
                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForAction] & RequiredBitForAction) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 0, RequiredPropertyActionNotPresent, "action"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 0, RequiredPropertyActionPresent, "action"u8, "required"u8);
                            }

