                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForFollowedBy] & RequiredBitForFollowedBy) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 4, RequiredPropertyFollowedByNotPresent, "followed-by"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 4, RequiredPropertyFollowedByPresent, "followed-by"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForMenuCode] & RequiredBitForMenuCode) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 5, RequiredPropertyMenuCodeNotPresent, "menu-code"u8, "required"u8);
                            }
                            else
                            {
